// Safely extract meetingId from Fireflies webhook
// Fireflies can send payload in different structures
const raw = $input.first().json;

// Handle all possible payload structures
const meetingId =
  raw.meetingId ||
  raw.body?.meetingId ||
  raw.data?.meetingId ||
  raw.payload?.meetingId ||
  '';

const eventType =
  raw.eventType ||
  raw.body?.eventType ||
  raw.data?.eventType ||
  'Transcription completed';

if (!meetingId) {
  return [{
    json: {
      isValid: false,
      error: 'No meetingId found in webhook payload',
      rawPayload: JSON.stringify(raw).substring(0, 200)
    }
  }];
}

return [{
  json: {
    isValid: true,
    meetingId: meetingId.trim(),
    eventType
  }
}];

