parameters.jsCode:
const response = $input.first().json;
const config = $('5. Set — Config Values').item.json;

const transcript = response?.data?.transcript;

if (!transcript || !transcript.id) {
  return [{
    json: {
      hasData: false,
      meetingId: config.meetingId,
      error: 'Transcript not found or not yet ready in Fireflies'
    }
  }];
}

// Build full conversation text from sentences
const sentences = transcript.sentences || [];
let fullText = '';
const taskLines = [];
const pricingLines = [];
const questionLines = [];

sentences.forEach(s => {
  const speaker = s.speaker_name || 'Speaker';
  const text = (s.text || '').trim();
  if (text) {
    fullText += `${speaker}: ${text}\n`;
    if (s.ai_filters?.task && text.length > 15) taskLines.push(text);
    if (s.ai_filters?.pricing && text.length > 15) pricingLines.push(text);
    if (s.ai_filters?.question && text.length > 15) questionLines.push(text);
  }
});

// Limit transcript text to 5000 chars for GPT token safety
const transcriptExcerpt = fullText.substring(0, 5000);

// Summary fields from Fireflies
const summary = transcript.summary || {};
const keywords = (summary.keywords || []).slice(0, 12).join(', ') || 'None';
const actionItems = (summary.action_items || []).slice(0, 5).join(' | ') || 'None';
const overview = (summary.overview || '').substring(0, 800);
const gist = summary.gist || '';
const bulletPoints = (summary.bullet_gist || []).slice(0, 6).join('\n') || '';

// Date formatting
const meetingDate = transcript.date
  ? new Date(transcript.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

const meetingTitle = transcript.title || 'Untitled Meeting';
const durationMin = Math.round((transcript.duration || 0) / 60);
const participants = (transcript.participants || []).join(', ') || 'Not listed';
const transcriptUrl = transcript.transcript_url || 'Not available';

const positivePct = Math.round(transcript.analytics?.sentiments?.positive_pct || 0);
const negativePct = Math.round(transcript.analytics?.sentiments?.negative_pct || 0);

const logDate = new Date().toISOString().replace('T', ' ').substring(0, 16);
const docTitle = `LinkedIn Post — ${meetingTitle} — ${meetingDate}`;

return [{
  json: {
    hasData: true,
    meetingId: transcript.id,
    meetingTitle,
    meetingDate,
    durationMin,
    participants,
    transcriptUrl,
    transcriptExcerpt,
    keywords,
    actionItems,
    overview,
    gist,
    bulletPoints,
    taskLines: taskLines.slice(0, 3).join(' | ') || 'None',
    pricingLines: pricingLines.slice(0, 3).join(' | ') || 'None',
    questionLines: questionLines.slice(0, 3).join(' | ') || 'None',
    positivePct,
    negativePct,
    docTitle,
    logDate,
    authorName: config.authorName,
    authorTitle: config.authorTitle,
    companyName: config.companyName,
    googleDriveFolderId: config.googleDriveFolderId,
    slackChannel: config.slackChannel
  }
}];

// Read AI output and prepare final fields for Drive + Slack
const aiPost = $input.first().json.output || '';
const data = $('7. Code — Process Transcript Data').item.json;

if (!aiPost || aiPost.length < 50) {
  return [{
    json: {
      linkedinPost: 'Post generation failed. Please check OpenAI credentials.',
      docTitle: data.docTitle,
      folderId: data.googleDriveFolderId,
      slackChannel: data.slackChannel,
      slackMessage: 'LinkedIn post generation failed for: ' + data.meetingTitle,
      meetingTitle: data.meetingTitle,
      meetingDate: data.meetingDate,
      transcriptUrl: data.transcriptUrl
    }
  }];
}

// Full document content for Google Drive
const docContent =
  'LINKEDIN POST DRAFT\n' +
  'Meeting: ' + data.meetingTitle + '\n' +
  'Date: ' + data.meetingDate + '\n' +
  'Author: ' + data.authorName + ', ' + data.authorTitle + '\n' +
  'Company: ' + data.companyName + '\n' +
  'Generated: ' + data.logDate + '\n' +
  '\n' +
  '============================================================\n' +
  'LINKEDIN POST — READY TO COPY AND PASTE\n' +
  '============================================================\n' +
  '\n' +
  aiPost +
  '\n\n' +
  '============================================================\n' +
  'MEETING REFERENCE\n' +
  '============================================================\n' +
  'Title: ' + data.meetingTitle + '\n' +
  'Date: ' + data.meetingDate + '\n' +
  'Duration: ' + data.durationMin + ' minutes\n' +
  'Participants: ' + data.participants + '\n' +
  'Fireflies Link: ' + data.transcriptUrl + '\n' +
  'Keywords: ' + data.keywords + '\n' +
  'Action Items: ' + data.actionItems + '\n' +
  '\n' +
  'Auto-generated by n8n + Fireflies.ai + GPT-4o-mini';

// Slack preview — first 350 chars of post
const preview = aiPost.length > 350 ? aiPost.substring(0, 350) + '...' : aiPost;

const slackMessage =
  '*New LinkedIn Post Draft Ready*\n' +
  '\n' +
  '*Meeting:* ' + data.meetingTitle + '\n' +
  '*Date:* ' + data.meetingDate + '   *Duration:* ' + data.durationMin + ' min\n' +
  '*Author:* ' + data.authorName + ', ' + data.authorTitle + '\n' +
  '\n' +
  '*POST PREVIEW:*\n' +
  preview +
  '\n\n' +
  '_Full post saved to Google Drive_\n' +
  '_Fireflies transcript: ' + data.transcriptUrl + '_';

return [{
  json: {
    linkedinPost: aiPost,
    docContent,
    docTitle: data.docTitle,
    folderId: data.googleDriveFolderId,
    slackChannel: data.slackChannel,
    slackMessage,
    meetingTitle: data.meetingTitle,
    meetingDate: data.meetingDate
  }
}];
